import React, { useState, useEffect, useMemo } from 'react';
import Select from 'react-select';
import './AddPurchase.css';
import AddMaterial from './AddMaterial'; 

const AddPurchase = ({ handleAdd, locations, vendors, materials }) => {

  const [showAddMaterialForm, setShowAddMaterialForm] = useState(false);

  const openAddMaterialForm = () => {
    setShowAddMaterialForm(true);
  };

  const initialPurchaseState = {
    location: '',
    materialid: '',
    materialname: '',
    quantity: '',
    price: '',
    vendor: '',
    vendorname: '',
    width: null,
    lotnumber: '',
  };

  const [newPurchase, setNewPurchase] = useState(initialPurchaseState);
  const [showExtras, setShowExtras] = useState(false);


  useEffect(() => {
    const fetchData = async () => {
      if (newPurchase.materialid) {
        try {
          const [responseChanges, responseList] = await Promise.all([
            fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`),
            fetch(`http://localhost:8081/materiallist/${newPurchase.materialid}`),
          ]);

          const [dataChanges, dataList] = await Promise.all([
            responseChanges.json(),
            responseList.json(),
          ]);

          if (dataList && dataList.extras === 1) {
            setShowExtras(true);
          } else {
            setShowExtras(false);
          }

          if (dataChanges && dataChanges.price && dataChanges.vendor) {
            const selectedVendor = vendors.find((vendor) => vendor.vendorid === dataChanges.vendor);
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              price: dataChanges.price,
              vendor: dataChanges.vendor,
              vendorname: selectedVendor ? selectedVendor.name : '',
            }));
          } else {
            setNewPurchase((prevPurchase) => ({
              ...prevPurchase,
              price: '',
              vendor: '',
              vendorname: '',
            }));
          }

          setNewPurchase((prevPurchase) => ({
            ...prevPurchase,
            materialname: dataList && dataList.name ? dataList.name : '',
          }));
        } catch (error) {
          console.error('Error fetching material data:', error);
        }
      } else {
        setShowExtras(false);
        setNewPurchase((prevPurchase) => ({
          ...prevPurchase,
          price: '',
          vendor: '',
          vendorname: '',
          materialname: '',
        }));
      }
    };

    fetchData();
  }, [newPurchase.materialid, vendors]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const selectedVendor = vendors.find((vendor) => vendor.name === newPurchase.vendorname);
    const updatedPurchase = {
      ...newPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
    };

    try {
      const responseChanges = await fetch(`http://localhost:8081/materialchangesAPI/${newPurchase.materialid}`);
      const dataChanges = await responseChanges.json();

      const hasChanges =
        dataChanges &&
        (dataChanges.price !== newPurchase.price ||
          dataChanges.vendor !== updatedPurchase.vendor);

      if (dataChanges && hasChanges) {
        const response = await fetch('http://localhost:8081/materialchangesAPI/', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            material_id: newPurchase.materialid,
            price: newPurchase.price,
            vendor: updatedPurchase.vendor,
          }),
        });

        if (!response.ok) {
          console.error('Failed to create material change:', response);
          return;
        }
      }

      handleAdd(newPurchase);

      setNewPurchase(initialPurchaseState);
    } catch (error) {
      console.error('Error handling the form submission:', error);
    }
  };

  const handleVendorChange = (selectedOption) => {
    if (!selectedOption) {
      setNewPurchase((prevPurchase) => ({
        ...prevPurchase,
        vendor: '',
        vendorname: '',
      }));
      return;
    }

    const selectedVendor = vendors.find((vendor) => vendor.name === selectedOption?.label);
    setNewPurchase((prevPurchase) => ({
      ...prevPurchase,
      vendor: selectedVendor ? selectedVendor.vendorid : '',
      vendorname: selectedOption ? selectedOption.label : '',
    }));
  };

  const vendorOptions = useMemo(
    () => vendors.map((vendor) => ({ value: vendor.name, label: vendor.name })),
    [vendors]
  );

  return (
    <div>
      <form onSubmit={handleSubmit} className="add-purchase-form">
        <div>
          <label>Location:</label>
          <select name="location" value={newPurchase.location} onChange={handleChange} required>
            <option value="">Select a location</option>
            {locations.map((location) => (
              <option key={location.id} value={location.id}>
                {location.locationname}
              </option>
            ))}
          </select>
        </div>
        <div>
          <label>Material ID:</label>
          <Select
            name="materialid"
            value={{ value: newPurchase.materialid || '', label: newPurchase.materialid || 'Select a material' }}
            options={materials.map((material) => ({
              value: material.matid,
              label: material.matid,
            }))}
            onChange={(selectedOption) => handleChange({ target: { name: 'materialid', value: selectedOption.value } })}
            required
          />
          <span className="add-material-icon" onClick={openAddMaterialForm}>
              +
            </span>
            {showAddMaterialForm && (
          <div className="add-material-overlay">
            <div className="add-material-popup">
              <span className="close-popup" onClick={() => setShowAddMaterialForm(false)}>
                &times;
              </span>
              <AddMaterial handleAdd={handleAdd} />
            </div>
          </div>
        )}
        </div>
        <div>
          <label>Material Name:</label>
          <input type="text" name="materialname" value={newPurchase.materialname} readOnly required />
        </div>
        {showExtras && (
          <div>
            <label>Width:</label>
            <input
              type="number"
              name="width"
              value={newPurchase.width || ''}
              onChange={handleChange}
              required
            />
          </div>
        )}
        {showExtras && (
          <div>
            <label>LOT#:</label>
            <input
              type="text"
              name="lotnumber"
              value={newPurchase.lotnumber || ''}
              onChange={handleChange}
              required
            />
          </div>
        )}
        <div>
          <label>Quantity:</label>
          <input type="text" name="quantity" value={newPurchase.quantity} onChange={handleChange} required />
        </div>
        <div>
          <label>Price:</label>
          <input
            type="text"
            name="price"
            value={newPurchase.price || ''}
            onChange={handleChange}
            required
          />
        </div>
        <div>
          <label>Vendor:</label>
          <Select
            options={vendorOptions}
            value={
              newPurchase.vendorname
                ? { value: newPurchase.vendorname, label: newPurchase.vendorname }
                : null
            }
            onChange={handleVendorChange}
            placeholder="Select a Vendor"
            isSearchable
            required
          />
        </div>
        <button type="submit" className="add_purchase_btn">
          Add Purchase
        </button>
      </form>
    </div>
  );
};

export default AddPurchase;
